import {
  useState,
  useEffect,
  useRef,
  useCallback,
  useMemo,
  memo,
  lazy,
  Suspense,
} from "react";
import { AnimatePresence } from "framer-motion";
import gsap from "gsap";
import SplitText from "gsap/SplitText";

import Container from "./layout/Container";
import Section from "./layout/Section";
import DownButton from "./layout/DownButton";
import Seperator from "./layout/seperator";
import API from "../api";

const ProductSheetModal = lazy(() => import("./ProductSheetModal"));

const cardStyles = `
  .product-card-wrap {
    position: relative;
    background-color: #1a1b1e;
    background-image: linear-gradient(135deg, rgba(255,255,255,0.25) 0%, rgba(255,255,255,0.05) 50%, rgba(255,255,255,0) 100%);
    transition: background-color 0.22s ease, border-color 0.22s ease;
    cursor: pointer;
    text-align: left;

    /* key spacing fix */
    padding: 36px 28px 28px 28px;

    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;

    gap: 25px;

    width: 100%;
    border: none;
    outline: none;
    aspect-ratio: 1 / .80;
    min-height: 0;
    min-width: 0;
    overflow: hidden;
  }

  @media (max-width: 640px) {
    .product-card-wrap {
      padding: 20px 18px;
      align-items: center;
      text-align: center;
      justify-content: center;
      gap: 6px;
    }
  }

  .product-card-wrap:hover {
    background-color: #3a2d00;
  }

  .product-card-wrap:hover .lc {
    border-color: rgba(230, 175, 0, 0.55);
  }

  /* text layout */
  .card-index {
    font-size: 0.70rem;
    color: #eee8cd;
    font-weight: 400;
    letter-spacing: 0.05em;
    margin: 0;
    opacity: .75;
  }

  .card-name {
    font-family: "Barlow Condensed", "SKODA Next Black Expanded", "SKODA Next", system-ui, sans-serif;
    font-weight: 800;
    font-size: clamp(1.15rem, 2.2vw, 1.55rem);
    color: #eee8cd;
    margin: 0;
    line-height: 1.15;
    letter-spacing: 0.01em;
  }

  .card-subtitle {
    font-family: "SKODA Next", system-ui, sans-serif;
    font-weight: 300;
    font-size: 0.72rem;
    color: #eee8cd;
    margin: 0;
    opacity: .85;
    line-height: 1.15;
    letter-spacing: 0.02em;
  }

  .product-card-wrap:hover .card-index   { color: rgba(240, 185, 0, 0.65); }
  .product-card-wrap:hover .card-name    { color: #f5c000; }
  .product-card-wrap:hover .card-subtitle { color: rgba(240, 185, 0, 0.55); }

  /* L corners */
  .lc {
    position: absolute;
    width: 14px;
    height: 14px;
    pointer-events: none;
    z-index: 2;
  }

  .lc-tl {
    top: 0; left: 0;
    border-top: 1.5px solid rgba(255,255,255,0.45);
    border-left: 1.5px solid rgba(255,255,255,0.45);
  }

  .lc-tr {
    top: 0; right: 0;
    border-top: 1.5px solid rgba(255,255,255,0.45);
    border-right: 1.5px solid rgba(255,255,255,0.45);
  }

  .lc-bl {
    bottom: 0; left: 0;
    border-bottom: 1.5px solid rgba(255,255,255,0.45);
    border-left: 1.5px solid rgba(255,255,255,0.45);
  }

  .lc-br {
    bottom: 0; right: 0;
    border-bottom: 1.5px solid rgba(255,255,255,0.45);
    border-right: 1.5px solid rgba(255,255,255,0.45);
  }

  /* grid */
  .product-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 0;
    max-width: 720px;
    margin-inline: auto;
  }

  .product-card-wrap {
    border-right: 1px solid rgba(255,255,255,0.10);
    border-bottom: 1px solid rgba(255,255,255,0.10);
  }

  @media (min-width: 641px) and (max-width: 1024px) {
    .product-grid {
      grid-template-columns: repeat(2, minmax(0, 1fr));
      margin-left: 0;
      max-width: 540px;
    }
  }

  @media (max-width: 640px) {
    .product-grid {
      grid-template-columns: repeat(2, 1fr);
      margin-left: 0;
      margin-right: 0;
      max-width: 100%;
    }
  }

  @media (max-width: 640px) {
    .product-card-wrap {
      justify-content: center;
      gap: 13px;
    }
  }

  @media (max-width: 640px) {
    .card-name    { font-size: 1.40rem; }
    .card-subtitle { font-size: 0.80rem; }
    .card-index   { font-size: 0.80rem; }
  }

  /* hide horizontal scrollbar (mobile) */
  .scrollbar-hide {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }
  .scrollbar-hide::-webkit-scrollbar { display: none; }

  /* ── scanline shimmer ── */
  @keyframes card-scanline {
    0%   { transform: translateY(-100%); opacity: 0.18; }
    100% { transform: translateY(220%);  opacity: 0; }
  }
  .card-shimmer {
    position: absolute;
    inset: 0;
    pointer-events: none;
    overflow: hidden;
    z-index: 3;
  }
  .card-shimmer::after {
    content: '';
    position: absolute;
    left: 0; right: 0;
    height: 38%;
    background: linear-gradient(
      to bottom,
      transparent 0%,
      rgba(245,192,0,0.06) 40%,
      rgba(245,192,0,0.12) 50%,
      rgba(245,192,0,0.06) 60%,
      transparent 100%
    );
    animation: card-scanline 0.72s cubic-bezier(0.4,0,0.2,1) forwards;
  }
`;

// Inject card styles once at module level — never re-injects on re-render or remount
const STYLE_ID = "bm-card-styles";
if (typeof document !== "undefined" && !document.getElementById(STYLE_ID)) {
  const styleEl = document.createElement("style");
  styleEl.id = STYLE_ID;
  styleEl.textContent = cardStyles;
  document.head.appendChild(styleEl);
}

export default function Materials() {
  const [categories, setCategories] = useState([]);
  const [products, setProducts] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedProduct, setSelectedProduct] = useState(null);

  const categoryListRef = useRef(null);

  // ── Animation refs ──
  const sectionLabelRef = useRef(null);
  const sectionTitleRef = useRef(null);
  const sectionParaRef = useRef(null);
  const categoryHeaderRef = useRef(null);
  const gridWrapRef = useRef(null);
  const categoryHeaderTlRef = useRef(null);
  const categoryHeaderSplitRef = useRef(null);

  // ── Section header: SplitText line reveal on scroll ──
  useEffect(() => {
    gsap.registerPlugin(SplitText);
    if (!sectionTitleRef.current) return;

    // guard: fire exactly once
    let triggered = false;
    const splits = [];

    const split = (el, opts) => {
      const s = SplitText.create(el, {
        linesClass: "overflow-hidden",
        ...opts,
      });
      splits.push(s);
      return s;
    };

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting || triggered) return;
          triggered = true;
          observer.disconnect();

          const tl = gsap.timeline({ defaults: { ease: "expo.out" } });

          tl.from(sectionLabelRef.current, {
            opacity: 0,
            y: 8,
            filter: "blur(4px)",
            duration: 0.5,
            clearProps: "opacity,y,filter",
          })
            .from(
              split(sectionTitleRef.current, { type: "lines" }).lines,
              {
                y: "105%",
                opacity: 0,
                duration: 0.85,
                stagger: 0.09,
                clearProps: "opacity,y,transform",
              },
              "-=0.3",
            )
            .from(
              split(sectionParaRef.current, { type: "lines" }).lines,
              {
                y: "105%",
                opacity: 0,
                duration: 0.7,
                stagger: 0.07,
                clearProps: "opacity,y,transform",
              },
              "-=0.5",
            );
        });
      },
      { threshold: 0.3 },
    );

    observer.observe(sectionTitleRef.current);

    return () => {
      observer.disconnect();
      // kill-then-revert: never revert while a tween is in flight
      splits.forEach((s) => s.revert());
    };
  }, []);

  // ── Category header: char-by-char stamp on every switch ──
  // Tracks the last-animated id so a categories-only re-render
  // (e.g. data fetch completing) doesn't re-fire for the same category.
  const lastAnimatedCategoryRef = useRef(null);

  useEffect(() => {
    const el = categoryHeaderRef.current;
    if (!el || !selectedCategory) return;

    // skip if this category was already animated (guards against categories dep re-run)
    if (lastAnimatedCategoryRef.current === selectedCategory) return;
    lastAnimatedCategoryRef.current = selectedCategory;

    // 1. Kill in-progress animation
    categoryHeaderTlRef.current?.kill();

    // 2. Revert previous split — restores DOM to plain text node
    categoryHeaderSplitRef.current?.revert();

    // 3. Set correct text now that DOM is clean
    const name = categories.find((c) => c._id === selectedCategory)?.name ?? "";
    el.textContent = name;

    // 4. Split the freshly-set text and animate
    categoryHeaderSplitRef.current = SplitText.create(el, {
      type: "chars",
      charsClass: "inline-block",
    });

    categoryHeaderTlRef.current = gsap.timeline({
      defaults: { ease: "expo.out" },
    });
    categoryHeaderTlRef.current.from(categoryHeaderSplitRef.current.chars, {
      y: 14,
      opacity: 0,
      scaleY: 1.15,
      filter: "blur(5px)",
      duration: 1,
      stagger: { each: 0.026, from: "start" },
      clearProps: "opacity,y,scaleY,filter,transform",
    });

    return () => {
      categoryHeaderTlRef.current?.kill();
      categoryHeaderSplitRef.current?.revert();
    };
  }, [selectedCategory, categories]);

  // ── Product grid: clip-path forge-in on category switch ──
  // Fix: single rAF (the double-rAF leaked the inner id on fast switches).
  // Fix: removed Framer motion.div wrapper — it fought GSAP on opacity/y.
  // Fix: shimmer restart uses void-reflow per card, no setTimeout chain.
  const animateGrid = useCallback(() => {
    if (!gridWrapRef.current) return;
    const cards = gridWrapRef.current.querySelectorAll(".product-card-wrap");
    if (!cards.length) return;

    gsap.killTweensOf(cards);
    gsap.set(cards, {
      opacity: 0,
      y: 24,
      scaleX: 0.97,
      filter: "blur(4px)",
      clipPath: "inset(100% 0% 0% 0%)",
    });

    gsap.to(cards, {
      opacity: 1,
      y: 0,
      scaleX: 1,
      filter: "blur(0px)",
      clipPath: "inset(0% 0% 0% 0%)",
      duration: 1.2,
      ease: "expo.out",
      stagger: { each: 0.052, from: "start", grid: "auto" },
      clearProps: "opacity,y,scaleX,filter,clipPath",
      onComplete() {
        // restart shimmer with void-reflow (reliable, no setTimeout chain)
        cards.forEach((card) => {
          const s = card.querySelector(".card-shimmer");
          if (!s) return;
          s.classList.remove("card-shimmer");
          void s.offsetWidth; // force reflow so CSS animation resets
          s.classList.add("card-shimmer");
        });
      },
    });

    const corners = gridWrapRef.current.querySelectorAll(".lc");
    gsap.killTweensOf(corners);
    gsap.set(corners, { opacity: 0 });
    gsap.to(corners, {
      opacity: 1,
      duration: 0.22,
      stagger: 0.01,
      delay: 0.18,
      ease: "power2.out",
      clearProps: "opacity",
    });
  }, []);

  useEffect(() => {
    // single rAF — cancels cleanly on fast category switches
    const raf = requestAnimationFrame(animateGrid);
    return () => cancelAnimationFrame(raf);
    // eslint-disable-next-line react-hooks/exhaustive-deps -- animateGrid is stable; category drives reruns
  }, [selectedCategory]);

  // ── original handler — unchanged ──
  const handleCategoryClick = (id, event) => {
    setSelectedCategory(id);
    if (
      window.innerWidth < 768 &&
      categoryListRef.current &&
      event?.currentTarget
    ) {
      const container = categoryListRef.current;
      const btn = event.currentTarget;
      const containerRect = container.getBoundingClientRect();
      const btnRect = btn.getBoundingClientRect();
      const centerOffset =
        btnRect.left +
        btnRect.width / 2 -
        (containerRect.left + containerRect.width / 2);
      container.scrollTo({
        left: container.scrollLeft + centerOffset,
        behavior: "smooth",
      });
    }
  };

  useEffect(() => {
    let mounted = true;

    const fetchData = async () => {
      try {
        const [catRes, prodRes] = await Promise.all([
          API.get("/categories"),
          API.get("/products?active=true"),
        ]);
        if (!mounted) return;

        const cats = catRes.data;
        const prods = prodRes.data;

        setCategories(cats);
        setProducts(prods);

       if (cats.length > 0 && !selectedCategory) {
  setSelectedCategory(cats[0]._id);
}
      } catch (err) {
        console.error("Failed to load materials data", err);
        if (mounted) setError("Unable to load materials data from the server.");
      } finally {
        if (mounted) setLoading(false);
      }
    };
    fetchData();
    return () => {
      mounted = false;
    };
  }, []);

  const filteredProducts = useMemo(() => {
  return products.filter((p) => {
    const catId =
      typeof p.category === "object"
        ? p.category?._id
        : p.category;

    return catId === selectedCategory;
  });
}, [products, selectedCategory]);

  const selectedCategoryName = useMemo(() => {
    return categories.find((c) => c._id === selectedCategory)?.name ?? "";
  }, [categories, selectedCategory]);

  return (
    <>
      <div id="materials">
        <Section className="min-h-[70vh] pt-6 md:pt-0">
          <Container>
            {/* Header row */}
            <div className="grid grid-cols-1 md:grid-cols-12 gap-y-1 md:gap-x-12 mb-6">
              <div className="md:col-span-3">
                <span
                  ref={sectionLabelRef}
                  className="text-sm uppercase tracking-wider"
                >
                  Our Materials
                </span>
              </div>
              <div className="md:col-span-9 md:justify-self-end max-w-[560px]">
                <h2
                  ref={sectionTitleRef}
                  className="text-3xl md:text-4xl font-skoda font-semibold text-yellow-400"
                >
                  From Furnace to Function
                </h2>
                <p ref={sectionParaRef} className="mt-4">
                  Our curated portfolio of raw materials combines performance,
                  purity, and sustainability, supporting high-temperature
                  manufacturing while advancing the collective goal of reducing
                  carbon footprints.
                </p>
              </div>
            </div>

            {/* Main panel */}
            <div
              className="rounded-2xl bg-slate-50/20"
              style={{ border: "1px solid rgba(255,255,255,0.08)" }}
            >
              {loading ? (
                <div className="flex items-center justify-center py-24">
                  <span className="text-sm text-white/40 uppercase tracking-widest">
                    Loading…
                  </span>
                </div>
              ) : error ? (
                <div className="flex flex-col items-center justify-center py-24 min-h-[420px]">
                  <span className="text-sm text-red-500/80 uppercase tracking-widest mb-4">
                    Error
                  </span>
                  <p className="text-white/60">{error}</p>
                </div>
              ) : (
                <div className="flex flex-col md:flex-row min-h-[420px]">
                  {/* ── Left sidebar ── */}
                  <div className="sticky top-[80px] md:top-[30px] z-30 rounded-t-2xl md:rounded-none bg-slate-50/20 backdrop-blur-md md:relative md:bg-transparent md:backdrop-blur-none md:w-65 flex-shrink-0 pt-5 pb-6 pl-9 pr-6 flex flex-col gap-1 border-b-2 border-white/[0.12] md:border-b-0 md:after:content-[''] after:hidden md:after:block after:absolute after:right-[-38px] after:top-[35px] after:bottom-[20px] after:w-[2px] after:bg-white/[0.12]">
                    {/* Sidebar header */}
                    <div className="flex items-center justify-center md:justify-start w-full gap-1.5 mb-3">
                      <svg
                        viewBox="0 0 18 18"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                        className="w-[22px] h-[22px] md:w-[35px] md:h-[35px] flex-shrink-0 opacity-80 relative top-[1px]"
                      >
                        <mask id="cat-icon-mask">
                          <rect
                            x="0"
                            y="0"
                            width="24"
                            height="24"
                            fill="white"
                          />
                          <rect
                            x="3.5"
                            y="3.5"
                            width="4.5"
                            height="4.5"
                            rx="0.5"
                            fill="none"
                            stroke="black"
                            strokeWidth="1.25"
                          />
                          <rect
                            x="10"
                            y="3.5"
                            width="4.5"
                            height="4.5"
                            rx="0.5"
                            fill="none"
                            stroke="black"
                            strokeWidth="1.25"
                          />
                          <rect
                            x="3.5"
                            y="10"
                            width="4.5"
                            height="4.5"
                            rx="0.5"
                            fill="none"
                            stroke="black"
                            strokeWidth="1.25"
                          />
                          <circle
                            cx="12.25"
                            cy="12.25"
                            r="2.25"
                            fill="none"
                            stroke="black"
                            strokeWidth="1.25"
                          />
                        </mask>

                        <rect
                          x="0"
                          y="0"
                          width="18"
                          height="18"
                          rx="4.5"
                          fill="#eee8cd"
                          mask="url(#cat-icon-mask)"
                        />
                      </svg>

                      <span className="text-[24px] md:text-[38px] font-light text-[#eee8cd] tracking-wide">
                        Categories
                      </span>
                    </div>
                    {/* Category list */}
                    <ul
                      ref={categoryListRef}
                      className="flex flex-row md:flex-col gap-1.5 overflow-x-auto pb-1 md:pb-0 scrollbar-hide"
                    >
                      {categories.map((cat) => {
                        const isActive = cat._id === selectedCategory;
                        return (
                          <li key={cat._id}>
                            <button
                              onClick={(e) => handleCategoryClick(cat._id, e)}
                              className={`whitespace-nowrap md:w-full text-left px-3 py-1.5 rounded-lg text-lg transition-all duration-150 ${
                                isActive
                                  ? "bg-gradient-to-r from-yellow-400/30 to-transparent text-yellow-400 font-semibold"
                                  : "text-white/50 hover:text-white/80 hover:bg-white/5"
                              }`}
                            >
                              {cat.name}
                            </button>
                          </li>
                        );
                      })}
                    </ul>

                    {/* Sidebar footer note */}
                    <div className="hidden md:block mt-auto pt-7">
                      <div className="w-[180px] h-[1px] bg-white/[0.18] mb-4"></div>
                      <p className="text-[13px] text-white/60 italic font-light tracking-[0.02em] mb-2">
                        Looking for the complete list?
                      </p>
                      <p className="text-[13.5px] text-white/95 font-semibold leading-[1.32] w-[220px]">
                        Get the full Sustainable Raw Materials chart in one
                        document.
                      </p>
                    </div>
                  </div>

                  {/* ── Right product grid ── */}
                  <div className="flex-1 pt-13 px-4 md:p-8 md:pl-14 flex flex-col">
                    {/* Grid header */}
                    <div className="hidden md:flex items-center justify-between mb-3 mt-4 ml-14 pl-0 md:pl-6">
                      <span className="text-[30px] font-light tracking-wide text-[#eee8cd] flex items-center gap-2">
                        <span className="opacity-70">→</span>
                        {/* ref on inner span; textContent managed by animation effect */}
                        <span ref={categoryHeaderRef}>
                          {selectedCategoryName}
                        </span>
                      </span>
                    </div>

                    {/* Product cards — Framer wrapper removed: it fought GSAP on opacity/y */}
                    {filteredProducts.length === 0 ? (
                      <div className="flex-1 flex items-center justify-center">
                        <p className="text-white/30 text-sm">
                          No products found for this category.
                        </p>
                      </div>
                    ) : (
                      <div ref={gridWrapRef} key={selectedCategory}>
                        <ProductGrid
                          products={filteredProducts}
                          onSelect={setSelectedProduct}
                        />
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Panel footer */}
              <div className="px-4 md:px-6 pt-6 pb-12 flex items-end justify-center mt-2 relative z-10">
                <a
                  href="/BM-SRM-Chart-2026.pdf"
                  target="_blank"
                  download
                  className="ml-50 max-md:ml-0"
                >
                  <DownButton>Download Full SRM Chart</DownButton>
                </a>
              </div>
            </div>
          </Container>
        </Section>
      </div>

      <Container>
        <Seperator />
      </Container>

      {/* Product Datasheet Modal — code-split: loads only when a card is opened */}
      <AnimatePresence>
        {selectedProduct && (
          <Suspense fallback={null}>
            <ProductSheetModal
              key="product-modal"
              product={selectedProduct}
              onClose={() => setSelectedProduct(null)}
            />
          </Suspense>
        )}
      </AnimatePresence>
    </>
  );
}

/* ─────────────────────────────────────────────
   ProductGrid — unchanged
───────────────────────────────────────────── */
const ProductGrid = memo(function ProductGrid({ products, onSelect }) {
  const COLS = 3;
  const rows = [];
  for (let i = 0; i < products.length; i += COLS) {
    rows.push(products.slice(i, i + COLS));
  }
  return (
    <div className="product-grid">
      {rows.map((row, rowIdx) => (
        <Row
          key={rowIdx}
          row={row}
          rowIdx={rowIdx}
          colSize={COLS}
          onSelect={onSelect}
        />
      ))}
    </div>
  );
});

const Row = memo(function Row({ row, rowIdx, colSize, onSelect }) {
  return (
    <>
      {row.map((product, colIdx) => {
        const globalIdx = rowIdx * colSize + colIdx;
        return (
          <button
            key={product._id}
            className="product-card-wrap"
            onClick={() => onSelect(product)}
            aria-label={`View details for ${product.name}`}
          >
            <span className="lc lc-tl" />
            <span className="lc lc-tr" />
            <span className="lc lc-bl" />
            <span className="lc lc-br" />
            <span className="card-shimmer" aria-hidden="true" />
            <span className="card-index">{globalIdx + 1}</span>
            <p className="card-name">{product.shortName || product.name}</p>
            <p className="card-subtitle">{product.name}</p>
          </button>
        );
      })}
    </>
  );
});

import { useState, useEffect, useMemo, memo } from "react";
import {
  FiPlus,
  FiEdit2,
  FiTrash2,
  FiSearch,
  FiGrid,
  FiChevronDown,
} from "react-icons/fi";
import { MdOutlineInventory2 } from "react-icons/md";
import Modal from "./Modal";
import ConfirmDialog from "./ConfirmDialog";
import ProductForm from "./ProductForm";
import { productImageSrc, PRODUCT_PLACEHOLDER_SRC } from "../../utils/productImage";

// ── ProductImageThumb ──────────────────────────────────────────────────
const ProductImageThumb = memo(function ProductImageThumb({ image, name }) {
  const [src, setSrc] = useState(() => productImageSrc(image));

  useEffect(() => {
    setSrc(productImageSrc(image));
  }, [image]);

  return (
    <img
      src={src}
      alt={name || "Product"}
      className="w-12 h-12 rounded-md object-contain border border-slate-200 shrink-0 bg-white"
      onError={() => setSrc(PRODUCT_PLACEHOLDER_SRC)}
    />
  );
});

// ── EmptyState ─────────────────────────────────────────────────────────
function EmptyState({ title, subtitle }) {
  return (
    <div className="py-20 text-center">
      <MdOutlineInventory2 className="text-slate-300 text-5xl mx-auto mb-3" />
      <p className="text-slate-500 font-medium text-sm">{title}</p>
      {subtitle && <p className="text-slate-400 text-xs mt-1">{subtitle}</p>}
    </div>
  );
}

// ── CategoryFilterPanel ────────────────────────────────────────────────
function CategoryFilterPanel({ categories, selectedId, onSelect }) {
  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden mb-5">
      <div className="px-4 py-2.5 bg-slate-50 border-b border-slate-100 flex items-center gap-2">
        <FiGrid className="text-indigo-500 text-xs" />
        <p className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
          Filter by Category
        </p>
        {selectedId && (
          <span className="ml-auto text-xs text-indigo-600 font-medium bg-indigo-50 px-2 py-0.5 rounded-full">
            {
              categories.find(function (c) {
                return String(c._id) === String(selectedId);
              })?.name
            }
          </span>
        )}
      </div>

      <div className="overflow-y-auto" style={{ maxHeight: "200px" }}>
        <button
          type="button"
          onClick={function () {
            onSelect(null);
          }}
          className={
            "w-full text-left px-4 py-2.5 text-sm flex items-center gap-2.5 transition cursor-pointer " +
            (!selectedId
              ? "bg-indigo-50 text-indigo-700 font-semibold"
              : "text-slate-600 hover:bg-slate-50")
          }
        >
          <span className="w-2 h-2 rounded-full bg-slate-300 shrink-0" />
          All Categories
        </button>

        {categories.map(function (c) {
          var isActive = String(selectedId) === String(c._id);
          return (
            <button
              key={c._id}
              type="button"
              onClick={function () {
                onSelect(c._id);
              }}
              className={
                "w-full text-left px-4 py-2.5 text-sm flex items-center gap-2.5 transition cursor-pointer border-t border-slate-50 " +
                (isActive
                  ? "bg-indigo-50 text-indigo-700 font-semibold"
                  : "text-slate-600 hover:bg-slate-50")
              }
            >
              <span
                className={
                  "w-2 h-2 rounded-full shrink-0 " +
                  (isActive ? "bg-indigo-500" : "bg-slate-200")
                }
              />
              {c.name}
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ── ProductSection ─────────────────────────────────────────────────────
function isProductActive(p) {
  return p.isActive !== false;
}

function ProductSection({
  products,
  categories,
  onAdd,
  onUpdate,
  onDelete,
  onToggleActive,
}) {
  // CRUD state
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState(null);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Search / filter state
  const [searchText, setSearchText] = useState("");
  const [filterMode, setFilterMode] = useState("all");
  const [selectedCategoryId, setSelectedCategoryId] = useState(null);

  // ── CRUD helpers ────────────────────────────────────────────────────
  // function openAdd  () {
    const openAdd = () => {
  setEditing(null);
    setModalOpen(true);
  }
  const openEdit=(p)=> {
    setEditing(p);
    setModalOpen(true);
  }
const closeModal = () => {
    setModalOpen(false);
    setEditing(null);
  }

  const handleSubmit = async (data) => {
    setIsSubmitting(true);
    try {
      if (editing) {
        await onUpdate(editing._id, data);
      } else {
        await onAdd(data);
      }
    } finally {
      setIsSubmitting(false);
      closeModal();
    }
  };

  function getProductCategoryId(p) {
    if (p.category && typeof p.category === "object")
      return String(p.category._id);
    return String(p.category || p.categoryId || "");
  }

  function getCategoryName(p) {
    if (p.category && typeof p.category === "object" && p.category.name) {
      return p.category.name;
    }
    var catId = p.category || p.categoryId || "";
    return (
      (
        categories.find(function (c) {
          return String(c._id) === String(catId);
        }) || {}
      ).name || "—"
    );
  }

  // ── Filter mode change ───────────────────────────────────────────────
  function handleFilterModeChange(e) {
    setFilterMode(e.target.value);
    setSelectedCategoryId(null);
  }

  function handleCategorySelect(id) {
    setSelectedCategoryId(id);
  }

  const filtered = useMemo(() => {
    const query = searchText.trim().toLowerCase();

    return products.filter((p) => {
      if (query && !p.name.toLowerCase().includes(query)) return false;

      if (filterMode === "active" && !isProductActive(p)) return false;
      if (filterMode === "inactive" && isProductActive(p)) return false;

      if (filterMode === "category" && selectedCategoryId) {
        if (getProductCategoryId(p) !== String(selectedCategoryId))
          return false;
      }

      return true;
    });
  }, [products, searchText, filterMode, selectedCategoryId]);

  const isFiltered =
    searchText.trim() !== "" ||
    (filterMode === "category" && selectedCategoryId) ||
    filterMode === "active" ||
    filterMode === "inactive";

  // ── Render ─────────────────────────────────────────────────────────────
  return (
    <div>
      {/* ── Header ───────────────────────────────────────────────────── */}
      <div className="flex flex-wrap items-start justify-between gap-3 mb-5 " >
        <div>
          <h2 className="text-slate-800 text-lg md:text-xl font-bold">
            All Products
          </h2>
          <p className="text-slate-500 text-sm mt-0.5">
            {isFiltered
              ? filtered.length + " of " + products.length + " products"
              : products.length + " products total"}
          </p>
        </div>
        <div className="flex gap-2">
       <button
  type="button"
  onClick={openAdd}
  className="flex items-center gap-2 px-4 py-2.5 rounded-xl cursor-pointer
  bg-gradient-to-r from-amber-400/30 via-yellow-300/50 to-amber-500/10
  text-black backdrop-blur-md border border-yellow-400/20
  hover:from-amber-400/40 hover:via-yellow-300/30 hover:to-amber-500/20
  transition-all"
>
  <FiPlus /> Add Product
</button>
        </div>
      </div>

      {/* ── Search + Filter mode bar ─────────────────────────────────── */}
      <div className="flex flex-col sm:flex-row gap-3 mb-4">
        <div className="relative flex-1">
          <FiSearch className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400 text-sm pointer-events-none" />
          <input
            type="text"
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            placeholder="Search products by name…"
            className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 text-slate-800 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-indigo-400 focus:border-indigo-400 transition placeholder-slate-400"
          />
          {searchText && (
            <button
              type="button"
              onClick={function () {
                setSearchText("");
              }}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 text-xs font-bold transition cursor-pointer"
              aria-label="Clear search"
            >
              ✕
            </button>
          )}
        </div>

        <div className="relative w-full sm:w-auto min-w-0">
          <select
            value={filterMode}
            onChange={handleFilterModeChange}
            className="appearance-none w-full min-w-0 sm:min-w-[140px] max-w-full pl-3 sm:pl-4 pr-9 py-2.5 rounded-xl border border-slate-200 bg-white text-slate-700 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-400 focus:border-indigo-400 transition cursor-pointer"
          >
            <option value="all">All products</option>
            <option value="active">Active only</option>
            <option value="inactive">Inactive only</option>
            <option value="category">By category…</option>
          </select>
          <FiChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm pointer-events-none" />
        </div>
      </div>

      {/* ── Active category filter chip (clear button) ───────────────── */}
      {filterMode === "category" && selectedCategoryId && (
        <div className="flex items-center gap-2 mb-3 -mt-1">
          <span className="text-slate-400 text-xs">Filtering by:</span>
          <span className="inline-flex items-center gap-1.5 pl-3 pr-1.5 py-1 bg-indigo-50 text-indigo-700 text-xs font-semibold rounded-full border border-indigo-200">
            {
              (
                categories.find(function (c) {
                  return String(c._id) === String(selectedCategoryId);
                }) || {}
              ).name
            }
            <button
              type="button"
              onClick={function () {
                setSelectedCategoryId(null);
              }}
              aria-label="Clear category filter"
              className="w-4 h-4 flex items-center justify-center rounded-full bg-indigo-200 hover:bg-indigo-300 text-indigo-700 transition cursor-pointer text-xs leading-none"
            >
              ×
            </button>
          </span>
        </div>
      )}

      {/* ── Category filter panel ─────────────────────────────────────── */}
      {filterMode === "category" && (
        <CategoryFilterPanel
          categories={categories}
          selectedId={selectedCategoryId}
          onSelect={handleCategorySelect}
        />
      )}

      {/* ── Desktop table ─────────────────────────────────────────────── */}
      <div className="hidden md:block bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        {filtered.length === 0 ? (
          products.length === 0 ? (
            <EmptyState
              title="No products yet."
              subtitle="Click Add Product to get started."
            />
          ) : (
            <EmptyState
              title="No products match your search."
              subtitle="Try a different name or category."
            />
          )
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr>
                  {[
                    "#",
                    "Product Name",
                    "Short Name",
                    "Category",
                    "Bulk Density",
                    "Fused Process",
                    "On site",
                    "Actions",
                  ].map(function (h) {
                    return (
                      <th
                        key={h}
                        className="px-4 py-3.5 text-xs font-semibold uppercase tracking-wider text-slate-500 whitespace-nowrap"
                      >
                        {h}
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filtered.map(function (p, idx) {
                  return (
                    <tr
                      key={p._id}
                      className="hover:bg-slate-50 transition-colors"
                    >
                      <td className="px-4 py-4 text-slate-400 font-mono text-xs w-10">
                        {String(idx + 1).padStart(2, "0")}
                      </td>
                      <td className="px-4 py-4">
                        <div className="flex items-center gap-2.5">
                          {/* ── Product image thumbnail (replaces ColorDots) ── */}
                          <ProductImageThumb image={p.image} name={p.name} />
                          <span className="text-slate-800 font-medium whitespace-nowrap">
                            {p.name}
                          </span>
                        </div>
                      </td>
                      <td className="px-4 py-4 text-slate-500 whitespace-nowrap">
                        {p.shortName}
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full bg-slate-100 text-slate-600 text-xs font-medium">
                          {getCategoryName(p)}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-slate-700 whitespace-nowrap">
                        {p.bulkDensity || "—"}
                      </td>
                      <td className="px-4 py-4 text-slate-500 max-w-[180px] truncate">
                        {p.fusedProcess || "—"}
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap">
                        <button
                          type="button"
                          role="switch"
                          aria-checked={isProductActive(p)}
                          title={
                            isProductActive(p)
                              ? "Visible on website — click to hide"
                              : "Hidden from website — click to show"
                          }
                          onClick={function () {
                            onToggleActive(p._id, !isProductActive(p));
                          }}
                          className={
                            "inline-flex h-7 w-12 shrink-0 cursor-pointer rounded-full p-0.5 transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-indigo-400 " +
                            (isProductActive(p)
                              ? "justify-end bg-emerald-500"
                              : "justify-start bg-slate-300")
                          }
                        >
                          <span className="pointer-events-none h-6 w-6 rounded-full bg-white shadow" />
                        </button>
                      </td>
                      <td className="px-4 py-4 w-24">
                        <div className="flex items-center gap-2">
                          <button
                            onClick={function () {
                              openEdit(p);
                            }}
                            title="Edit"
                            className="p-2 rounded-lg text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 transition cursor-pointer"
                          >
                            <FiEdit2 className="text-sm" />
                          </button>
                          <button
                            onClick={function () {
                              setDeleteTarget(p);
                            }}
                            title="Delete"
                            className="p-2 rounded-lg text-slate-400 hover:bg-red-50 hover:text-red-500 transition cursor-pointer"
                          >
                            <FiTrash2 className="text-sm" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* ── Mobile cards ──────────────────────────────────────────────── */}
      <div className="md:hidden">
        {filtered.length === 0 ? (
          products.length === 0 ? (
            <EmptyState title="No products yet." />
          ) : (
            <EmptyState
              title="No products match your search."
              subtitle="Try a different name or category."
            />
          )
        ) : (
          <div className="space-y-3">
            {filtered.map(function (p, idx) {
              return (
                <div
                  key={p._id}
                  className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4"
                >
                  <div className="flex items-start justify-between gap-3">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1.5">
                        <span className="text-slate-400 font-mono text-xs">
                          {String(idx + 1).padStart(2, "0")}
                        </span>
                        {/* ── Product image thumbnail (replaces ColorDots) ── */}
                        <ProductImageThumb image={p.image} name={p.name} />
                      </div>
                      <p className="text-slate-800 font-semibold text-sm truncate">
                        {p.name}
                      </p>
                      <p className="text-slate-400 text-xs mt-0.5">
                        <span className="text-indigo-600 font-medium">
                          {p.shortName}
                        </span>
                        {" · "}
                        <span className="bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded-full text-xs">
                          {getCategoryName(p)}
                        </span>
                      </p>
                      {(p.bulkDensity || p.fusedProcess) && (
                        <p className="text-slate-400 text-xs mt-0.5">
                          {p.bulkDensity ? "Bulk: " + p.bulkDensity : ""}
                          {p.bulkDensity && p.fusedProcess ? " · " : ""}
                          {p.fusedProcess || ""}
                        </p>
                      )}
                      <div className="flex items-center gap-2 mt-2">
                        <span className="text-[11px] text-slate-500 font-medium">
                          On site
                        </span>
                        <button
                          type="button"
                          role="switch"
                          aria-checked={isProductActive(p)}
                          onClick={function () {
                            onToggleActive(p._id, !isProductActive(p));
                          }}
                          className={
                            "inline-flex h-7 w-12 shrink-0 cursor-pointer rounded-full p-0.5 transition-colors " +
                            (isProductActive(p)
                              ? "justify-end bg-emerald-500"
                              : "justify-start bg-slate-300")
                          }
                        >
                          <span className="pointer-events-none h-6 w-6 rounded-full bg-white shadow" />
                        </button>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-2 mt-3 pt-3 border-t border-slate-100">
                    <button
                      onClick={function () {
                        openEdit(p);
                      }}
                      className="flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg border border-slate-200 text-slate-500 text-xs font-medium hover:border-indigo-300 hover:text-indigo-600 transition cursor-pointer"
                    >
                      <FiEdit2 className="text-xs" /> Edit
                    </button>
                    <button
                      onClick={function () {
                        setDeleteTarget(p);
                      }}
                      className="flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg border border-slate-200 text-slate-500 text-xs font-medium hover:border-red-300 hover:text-red-500 transition cursor-pointer"
                    >
                      <FiTrash2 className="text-xs" /> Delete
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ── Add / Edit Modal ──────────────────────────────────────────── */}
      <Modal
        isOpen={modalOpen}
        onClose={closeModal}
        title={editing ? "Edit: " + editing.name : "Add New Product"}
        size="xl"
      >
        <ProductForm
          key={editing?._id || "new"}
          initial={editing}
          categories={categories}
          onSubmit={handleSubmit}
          onCancel={closeModal}
        />
      </Modal>

      <ConfirmDialog
        isOpen={!!deleteTarget}
        onClose={function () {
          setDeleteTarget(null);
        }}
        onConfirm={function () {
          onDelete(deleteTarget._id);
          setDeleteTarget(null);
        }}
        message={
          'Are you sure you want to delete "' +
          (deleteTarget ? deleteTarget.name : "") +
          '"? This action cannot be undone.'
        }
      />
    </div>
  );
}

