import API from "../api";

let isRefreshing = false;
let failedQueue = [];

// Process queued requests after token refresh
const processQueue = (error, token = null) => {
  failedQueue.forEach(prom => {
    if (error) {
      prom.reject(error);
    } else {
      prom.resolve(token);
    }
  });

  failedQueue = [];
};

// Add request interceptor for automatic token refresh
API.interceptors.response.use(
  (response) => response,
  async (error) => {
    const originalRequest = error.config;

    if (error.response?.status === 401 && !originalRequest._retry) {
      if (isRefreshing) {
        // If already refreshing, queue the request
        return new Promise((resolve, reject) => {
          failedQueue.push({ resolve, reject });
        }).then(() => {
          return API(originalRequest);
        }).catch(err => {
          return Promise.reject(err);
        });
      }

      originalRequest._retry = true;
      isRefreshing = true;

      try {
        // Try to refresh the token
        await API.post("/admin/refresh");
        processQueue(null);
        // Retry the original request
        return API(originalRequest);
      } catch (refreshError) {
        processQueue(refreshError, null);
        // If refresh fails, logout
        logout();
        return Promise.reject(refreshError);
      } finally {
        isRefreshing = false;
      }
    }

    return Promise.reject(error);
  }
);

/**
 * Check if admin is logged in by calling /me endpoint
 */
export async function checkAuthStatus() {
  try {
    const response = await API.get("/admin/me");
    return {
      isLoggedIn: true,
      admin: response.data.admin
    };
  } catch (error) {
    return {
      isLoggedIn: false,
      admin: null
    };
  }
}

/**
 * Logout admin - clear session on server
 */
export async function logout() {
  try {
    await API.post("/admin/logout");
  } catch (error) {
    console.error("Logout error:", error);
  }
  // Clear any local state if needed
}

/**
 * Get current admin data (requires server call)
 */
export async function getAdmin() {
  const authStatus = await checkAuthStatus();
  return authStatus.admin;
}

